def solve(deps: dict[str, list[str]]) -> list[list[str]]:
    from collections import defaultdict

    # Collect all tasks
    tasks = set(deps.keys())
    for prereqs in deps.values():
        for p in prereqs:
            tasks.add(p)

    # Build graph: edge from prereq -> task
    in_degree = {t: 0 for t in tasks}
    graph = defaultdict(list)  # prereq -> list of tasks that depend on it
    for task, prereqs in deps.items():
        for p in prereqs:
            graph[p].append(task)
            in_degree[task] += 1

    # Kahn's algorithm with layering
    current_layer = sorted([t for t in tasks if in_degree[t] == 0])
    layers = []
    processed = 0

    while current_layer:
        layers.append(current_layer)
        processed += len(current_layer)
        next_layer_set = set()
        for node in current_layer:
            for neighbor in graph[node]:
                in_degree[neighbor] -= 1
                if in_degree[neighbor] == 0:
                    next_layer_set.add(neighbor)
        current_layer = sorted(next_layer_set)

    if processed != len(tasks):
        return []
    return layers
```

