from collections import OrderedDict

def solve(capacity: int, ops: list[str]) -> list[int]:
    if capacity == 0:
        return [-1 if op.startswith("get") else 0 for op in ops]

    cache = OrderedDict()
    res = []

    for op in ops:
        if op.startswith("get"):
            key = int(op.split()[1])
            if key in cache:
                cache.move_to_end(key)
                res.append(cache[key])
            else:
                res.append(-1)
        else:
            _, key, value = op.split()
            key, value = int(key), int(value)
            if key in cache:
                cache.move_to_end(key)
            elif len(cache) == capacity:
                cache.popitem(last=False)
            cache[key] = value
            res.append(0)

    return res
