import bisect

def solve(nums: list[int], k: int) -> list[float]:
    if not nums or k <= 0 or k > len(nums):
        return []

    # left: 有序列表存储较小一半，降序
    # right: 有序列表存储较大一半，升序
    left, right = [], []

    def add(num):
        # 插入到对应列表
        if not left or num <= left[-1]:
            bisect.insort(left, num)
        else:
            bisect.insort(right, num)
        # 平衡两个列表
        balance()

    def remove(num):
        # 从对应列表移除
        if num <= left[-1]:
            idx = bisect.bisect_left(left, num)
            left.pop(idx)
        else:
            idx = bisect.bisect_left(right, num)
            right.pop(idx)
        balance()

    def balance():
        # 确保 left 大小等于 right 或多一个
        if len(left) > len(right) + 1:
            val = left.pop()
            bisect.insort(right, val)
        elif len(right) > len(left):
            val = right.pop(0)
            bisect.insort(left, val)

    def get_median():
        if k % 2 == 1:
            return float(left[-1])
        else:
            return (left[-1] + right[0]) / 2.0

    result = []
    for i in range(len(nums)):
        add(nums[i])
        if i >= k - 1:
            result.append(get_median())
            remove(nums[i - k + 1])

    return result
```

