from collections import deque, defaultdict

def solve(deps: dict[str, list[str]], changed: list[str]) -> list[str]:
    # 收集所有包名
    all_packages = set(deps.keys())
    for dep_list in deps.values():
        all_packages.update(dep_list)
    all_packages.update(changed)

    # 构建反向依赖图
    reverse_deps = defaultdict(list)
    for pkg, dep_list in deps.items():
        for dep in dep_list:
            reverse_deps[dep].append(pkg)

    # 初始化受影响的集合和队列
    affected = set(changed)
    queue = deque(changed)

    # BFS
    while queue:
        p = queue.popleft()
        for q in reverse_deps.get(p, []):
            if q not in affected:
                affected.add(q)
                queue.append(q)

    # 返回排序后的列表
    return sorted(affected)
